import javax.jws.WebService;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import org.w3c.dom.Node;
import org.w3c.dom.Element;
import java.io.ByteArrayInputStream;

@WebService(endpointInterface = "com.example.SOAPService")
public class SOAPServiceImpl implements SOAPService {

    @Override
    public String processXML(String xmlData) {
        try {
            DocumentBuilderFactory dbFactory = DocumentBuilderFactory.newInstance();
            DocumentBuilder dBuilder = dbFactory.newDocumentBuilder();
            
            ByteArrayInputStream inputStream = new ByteArrayInputStream(xmlData.getBytes());
            Document doc = dBuilder.parse(inputStream);
            doc.getDocumentElement().normalize();

            NodeList nodeList = doc.getElementsByTagName("Entity");
            for (int i = 0; i < nodeList.getLength(); i++) {
                Node node = nodeList.item(i);
                if (node.getNodeType() == Node.ELEMENT_NODE) {
                    Element element = (Element) node;
                    String entityId = element.getAttribute("id");
                    processEntityData(element, entityId);
                }
            }

            return "XML processed successfully";
        } catch (Exception e) {
            e.printStackTrace();
            return "Error processing XML: " + e.getMessage();
        }
    }

    private void processEntityData(Element entityElement, String entityId) {
        // Example processing logic
        NodeList childNodes = entityElement.getChildNodes();
        for (int i = 0; i < childNodes.getLength(); i++) {
            Node childNode = childNodes.item(i);
            if (childNode.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) childNode;
                String tagName = childElement.getTagName();
                String value = childElement.getTextContent();
                // Process each element based on its tag name and value
                System.out.println("Processing " + tagName + ": " + value);
            }
        }
    }
}

interface SOAPService {
    String processXML(String xmlData);
}